-- 2084_rewrite_exercise_instructions.sql
-- Auto-generated by backend/scripts/rewrite_exercise_instructions.py.
-- Rewrites deficient exercise instructions using the app's own vetted
-- instruction engine, routed by a correct deterministic classifier.
-- Backs up originals first. NO LLM. The MV refresh is NOT here —
-- apply_2084_rewrite.py runs it separately (REFRESH ... CONCURRENTLY
-- cannot run inside a transaction).

CREATE TABLE IF NOT EXISTS public.exercise_instruction_backup (
    id uuid NOT NULL,
    source_table text NOT NULL,
    old_instructions text,
    new_instructions text,
    movement_class text,
    rewrite_method text NOT NULL DEFAULT 'rule',
    source_citation text,
    rewrite_batch text NOT NULL,
    backed_up_at timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (id, rewrite_batch)
);

INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Set the pad at your hip crease so you can hinge freely, ankles secured under the rollers.
2. Cross your arms on your chest (or place fingertips at your temples) and brace your core.
3. Hinge DOWN at the hips with a flat, neutral spine — this is a hip hinge, not a back bend.
4. Lower until you feel a stretch in the hamstrings, with the torso pointing toward the floor.
5. Raise back up by squeezing the glutes; stop in a straight line, do not arch past it.
6. Breathing: Inhale as you lower under control. Exhale as you raise back up. Keep the core braced throughout — do not hold your breath.
7. Form check: Keep a neutral spine the whole rep — never round or yank the lower back.
8. Form check: Finish in a straight line; hyperextending hard at the top stresses the spine.
9. The 45 Degree Hyperextension (Arms In Front Of Chest) mainly trains your Lower Back (erector spinae), Glutes (gluteus maximus, gluteus mideus). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'back_extension',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=back_extension] NSCA ESSC 4th ed. ch.13; McGill, Low Back Disorders 2nd ed. — neutral-spine hip hinge$instr$, '2085-2026-05-18'
FROM public.exercise_library WHERE id = 'b942f7f6-f23f-442d-8038-2d2c33da5e56'
  AND NOT EXISTS (SELECT 1 FROM public.exercise_instruction_backup
                  WHERE id = 'b942f7f6-f23f-442d-8038-2d2c33da5e56');
UPDATE public.exercise_library SET instructions = $instr$1. Set the pad at your hip crease so you can hinge freely, ankles secured under the rollers.
2. Cross your arms on your chest (or place fingertips at your temples) and brace your core.
3. Hinge DOWN at the hips with a flat, neutral spine — this is a hip hinge, not a back bend.
4. Lower until you feel a stretch in the hamstrings, with the torso pointing toward the floor.
5. Raise back up by squeezing the glutes; stop in a straight line, do not arch past it.
6. Breathing: Inhale as you lower under control. Exhale as you raise back up. Keep the core braced throughout — do not hold your breath.
7. Form check: Keep a neutral spine the whole rep — never round or yank the lower back.
8. Form check: Finish in a straight line; hyperextending hard at the top stresses the spine.
9. The 45 Degree Hyperextension (Arms In Front Of Chest) mainly trains your Lower Back (erector spinae), Glutes (gluteus maximus, gluteus mideus). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$ WHERE id = 'b942f7f6-f23f-442d-8038-2d2c33da5e56';

INSERT INTO public.exercise_instruction_backup
  (id, source_table, old_instructions, new_instructions, movement_class,
   source_citation, rewrite_batch)
SELECT id, 'exercise_library', instructions, $instr$1. Kneel on a mat (stand only if advanced), gripping the wheel directly under your shoulders.
2. Brace your core hard and tuck the pelvis so the lower back cannot arch.
3. Roll the wheel forward slowly, extending only as far as you keep the back flat.
4. Stop before the hips sag or the lower back arches — that point is your range.
5. Pull through your core to roll the wheel back to the start.
6. Breathing: Inhale and brace before rolling out. Exhale as you roll the wheel back in. Hold the brace the whole rep — do not hold your breath.
7. Form check: Never let the lower back arch — shorten the range instead.
8. Form check: Beginners: start with a short range or roll out toward a wall, then extend over time.
9. The Ab Wheel All The Way Out mainly trains your Abdominals (rectus abdominis). If you are newer to it, start light and add load only once the movement feels controlled, and on heavier sets end the set when your form or brace breaks down rather than grinding out a risky rep.$instr$, 'ab_wheel',
  $instr$[rule | engine=exercise_instruction_copy.dart | class=ab_wheel] NASM EPFT 6th ed. ch.9; McGill, Low Back Disorders 2nd ed. — trunk / core training$instr$, '2085-2026-05-18'
